mapper.select:
SELECT * FROM ( SELECT member_id, is_admin, email, nickname, user_intro, TO_CHAR(reg_dt, 'YYYY-MM-DD HH24:MI:SS') AS reg_dt, TO_CHAR(mod_dt, 'YYYY-MM-DD HH24:MI:SS') AS mod_dt, ROW_NUMBER() OVER (ORDER BY member_id DESC) AS rn FROM member
AND ( email LIKE '%' || #{searchWord} || '%' OR nickname LIKE '%' || #{searchWord} || '%' )
) WHERE rn BETWEEN ((#{pageNo} - 1) * #{pageSize} + 1) AND (#{pageNo} * #{pageSize}) ORDER BY rn

SELECT * FROM ( SELECT a.artwork_id, a.member_id, a.category_id, a.is_status, a.title, a.view_count, TO_CHAR(a.reg_dt, 'YYYY-MM-DD HH24:MI:SS') AS reg_dt, TO_CHAR(a.comp_dt, 'YYYY-MM-DD HH24:MI:SS') AS comp_dt, m.nickname, c.category_nm, (SELECT COUNT(*) FROM board_like l WHERE l.target_type = 'ARTWORK' AND l.target_id = a.artwork_id) AS like_count, ROW_NUMBER() OVER (ORDER BY a.artwork_id DESC) AS rn FROM artwork a JOIN member m ON a.member_id = m.member_id JOIN category c ON a.category_id = c.category_id
AND a.is_status = #{isStatus}
AND ( a.title LIKE '%' || #{searchWord} || '%' OR m.nickname LIKE '%' || #{searchWord} || '%' )
) WHERE rn BETWEEN ((#{pageNo} - 1) * #{pageSize} + 1) AND (#{pageNo} * #{pageSize}) ORDER BY rn

SELECT COUNT(*) FROM artwork a JOIN member m ON a.member_id = m.member_id JOIN category c ON a.category_id = c.category_id
AND a.is_status = #{isStatus}
AND ( a.title LIKE '%' || #{searchWord} || '%' OR m.nickname LIKE '%' || #{searchWord} || '%' )
